SELECT id, account, password_hash, name, status, last_login_at
FROM admin_user
WHERE account = #{account}

SELECT id, account, password_hash, name, status, last_login_at
FROM admin_user
WHERE id = #{adminId}

SELECT id, code, name, description, status, built_in
FROM admin_role
WHERE id = #{roleId}

SELECT id, code, name, description, status, built_in
FROM admin_role
WHERE code = #{code}

SELECT id, code, name, description, status, built_in FROM admin_role WHERE id IN
#{roleId}
ORDER BY id

SELECT id, code, name, category, permission_type, status FROM admin_permission WHERE status = 1 AND id IN
#{permissionId}
ORDER BY id

SELECT COUNT(1)
FROM admin_user_role
WHERE role_id = #{roleId}
